import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyTable, EditableCellMapFormat, MyListCardMenuPopup } from '../../../includes';
import { routeNamesInventory } from '../../routeNames';
import BrandHeaderComponent from './BrandHeaderComponent';
import { supplierStrings } from '../config';
import { supplierActions } from '../actions';
import { TextField } from '@material-ui/core';

const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Brands extends Component {
    constructor(props) {
        super(props);
        this.state = {
            brands : null,
            brandsUnusable : null,
            lastId : null,
            rows : null
        }
        const{dispatch}=props;
        headerActions({
            [headerStrings.headerTitle] : "BRANDS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Brands", path : routeNamesInventory.supplierBrands},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                BrandHeaderComponent
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [supplierStrings.supplierBrands] : supplierBrands
        } = this.props;
        const {lastId, rows} = this.state;
        supplierActions.getSupplierBrands(lastId, rows)(dispatch);
        supplierActions.getStockCategories()(dispatch);
        supplierActions.getAllSuppliersBrief()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [supplierStrings.supplierBrands] : brands
        } = props;
        if(!state.brandsUnusable && brands){
            state.brandsUnusable = state.brands = brands;
        }else if (JSON.stringify(state.brandsUnusable) !==
        JSON.stringify(brands)){
            state.brandsUnusable = state.brands = brands;
        }
        return state;
    }
    cellMapFormat = superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>;
    tableCellContentView = (stockCategories, suppliers) => (editing, {row, cellMap})=>{
        if(editing){
            switch(cellMap){
                case "stockCategoryId" : 
                return <MyListCardMenuPopup
                myListCardProps={{
                    elevation : 0,
                    itemNameProp : "name",
                    list : stockCategories,
                    listItemProps : {
                        button : true,
                    },
                    listItemClick : (item, index)=>console.log(item, index),
                }}
                />
                case "supplierId" : 
                return <MyListCardMenuPopup
                myListCardProps={{
                    elevation : 0,
                    itemNameProp : "name",
                    list : suppliers,
                    listItemProps : {
                        button : true,
                    },
                    listItemClick : (item, index)=>console.log(item, index),
                }}
                />
                default : return <TextField/>
            }
        }else{
            switch(cellMap){
                case "stockCategoryId" : 
                    if(stockCategories){
                        const {item} = stockCategories.getFirstObjectByPropValue(
                            "_id", parseInt(row[cellMap]
                        )) || {};
                        return item ? item.name : null;
                    }else return null
                case "supplierId" : 
                    if(suppliers){
                        const {item} = suppliers.getFirstObjectByPropValue(
                            "_id", parseInt(row[cellMap]
                        )) || {};
                        return item ? item.name : null;
                    }else return null
                default : return row[cellMap];
            }
        }
    }
    render() {
        const {
            classes, [supplierStrings.supplierBrandEditMode] : editMode,
            [supplierStrings.stockCategories] : stockCategories,
            [supplierStrings.allSupplierBrief] : allSupplierBrief,
        } = this.props;
        let {brands} = this.state;
        let header = ["ID", "Name", "Supplier", "Stock Category"];
        let dataMap = ["_id", "name", "supplierId", "stockCategoryId"];
        if(editMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            brands = brands ? 
                [...brands.map(item=>({...item, editable:true,delible:true})), {new:true}]:
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={brands || []}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"],
                        tableCellContentView : this.tableCellContentView(stockCategories, allSupplierBrief),
                    })}
                    />
            </div>
        );
    }
}


_Brands.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({supplierReducer}) => ({
    [supplierStrings.supplierBrandEditMode] : supplierReducer[supplierStrings.supplierBrandEditMode],
    [supplierStrings.supplierBrands] : supplierReducer[supplierStrings.supplierBrands],
    [supplierStrings.stockCategories] : supplierReducer[supplierStrings.stockCategories],
    [supplierStrings.allSupplierBrief] : supplierReducer[supplierStrings.allSupplierBrief],
})


export const Brands = connect(mapStateToProps)(withStyles(style)(_Brands));
export {Brands as default}