import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { DefaultMainStageHeader } from '../../../includes';
import { supplierStrings } from '../config';
import { supplierActions } from '../actions';


const style = theme => ({
    root: {
    }
})
class _BrandHeaderComponent extends Component {
    editBtnHandler = () => {
        const {
            dispatch,
            [supplierStrings.supplierBrandEditMode] : editMode
        } = this.props;
        if(editMode){
            //do something
        }
        supplierActions.setBrandEditMode(!Boolean(editMode))(dispatch);
    }
    cancelEditHandler = () => {
        const {dispatch} = this.props;
        supplierActions.setBrandEditMode(false)(dispatch);
    }
    render() {
        const {
            classes,
            [supplierStrings.supplierBrandEditMode] : supplierBrandEditMode,
        } = this.props;
        return (
            <DefaultMainStageHeader
                editMode={supplierBrandEditMode}
                editBtnHandler={this.editBtnHandler.bind(this)}
                cancelEditHandler={this.cancelEditHandler.bind(this)}
                />
        );
    }
}


_BrandHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({supplierReducer}) => ({
    [supplierStrings.supplierBrandEditMode] : supplierReducer[supplierStrings.supplierBrandEditMode],
})


export const BrandHeaderComponent = connect(mapStateToProps)(withStyles(style)(_BrandHeaderComponent));
export {BrandHeaderComponent as default}